    @_mutmut_mutated(mutants_xǁSchedulerAgentǁevaluate__mutmut)
    def evaluate(
        self,
        num_episodes: int = 10,
        deterministic: bool = True,
    ) -> dict[str, float]:
        """
        评估训练好的智能体性能

        运行指定数量的评估回合，统计平均奖励和任务调度成功率。

        Args:
            num_episodes: 评估回合数，默认 10
            deterministic: 是否使用确定性策略，默认 True

        Returns:
            评估结果字典，包含：
                - mean_reward: 平均累积奖励
                - std_reward: 奖励标准差
                - success_rate: 成功率（平均每回合完成率）
                - num_episodes: 评估回合数
        """
        if self.model is None:
            raise RuntimeError("模型尚未训练！请先调用 train() 方法或使用 load() 加载已训练模型。")

        episode_rewards = []
        episode_success_rates = []

        for _ep in range(num_episodes):
            obs, info = self.env.reset()
            total_reward = 0.0
            done = False

            while not done:
                action = self.predict(obs, deterministic=deterministic)
                obs, reward, terminated, truncated, info = self.env.step(action)
                total_reward += reward
                done = terminated or truncated

            episode_rewards.append(total_reward)

            # 从 info 中提取完成率作为成功率
            completion_rate = info.get("completion_rate", 0.0)
            episode_success_rates.append(completion_rate)

        result = {
            "mean_reward": float(np.mean(episode_rewards)),
            "std_reward": float(np.std(episode_rewards)),
            "success_rate": float(np.mean(episode_success_rates)),
            "num_episodes": num_episodes,
        }

        return result

