        # 合并回调
        callback = CallbackList(callbacks) if len(callbacks) > 1 else callbacks[0]

        tb_log_name = log_dir if log_dir else "ppo_scheduling"

        self.model.learn(
            total_timesteps=total_timesteps,
            callback=callback,
            tb_log_name=tb_log_name,
            reset_num_timesteps=True,
            **kwargs,
        )

        return self.model

